"use strict";(globalThis.webpackChunkspark_study=globalThis.webpackChunkspark_study||[]).push([[8954],{6844(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"week-1-caching-vs-checkpointing","metadata":{"permalink":"/spark-study/blog/week-1-caching-vs-checkpointing","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-02-22-cache-checkpoint-kwon.md","source":"@site/blog/2026-02-22-cache-checkpoint-kwon.md","title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","description":"Spark \uc131\ub2a5 \ucd5c\uc801\ud654\uc758 \ud575\uc2ec\uc778 Caching(StorageLevel)\uacfc Checkpointing\uc758 \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uae4a\uc774 \uc788\uac8c \ube44\uad50\ud558\uace0, \uc2e4\ubb34 \uc801\uc6a9 \uae30\uc900\uc744 \uc815\ub9ac\ud55c\ub2e4.","date":"2026-02-22T00:00:00.000Z","tags":[{"inline":true,"label":"spark","permalink":"/spark-study/blog/tags/spark"},{"inline":true,"label":"scala","permalink":"/spark-study/blog/tags/scala"},{"inline":true,"label":"optimization","permalink":"/spark-study/blog/tags/optimization"},{"inline":true,"label":"caching","permalink":"/spark-study/blog/tags/caching"},{"inline":true,"label":"checkpointing","permalink":"/spark-study/blog/tags/checkpointing"}],"readingTime":3.59,"hasTruncateMarker":false,"authors":[{"name":"Kwon Younglin","title":"Data Engineer","url":"https://github.com/kwonyl14","imageURL":"https://github.com/kwonyl14.png","key":"kwonyl14","page":null}],"frontMatter":{"slug":"week-1-caching-vs-checkpointing","title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","authors":["kwonyl14"],"tags":["spark","scala","optimization","caching","checkpointing"],"description":"Spark \uc131\ub2a5 \ucd5c\uc801\ud654\uc758 \ud575\uc2ec\uc778 Caching(StorageLevel)\uacfc Checkpointing\uc758 \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uae4a\uc774 \uc788\uac8c \ube44\uad50\ud558\uace0, \uc2e4\ubb34 \uc801\uc6a9 \uae30\uc900\uc744 \uc815\ub9ac\ud55c\ub2e4."},"unlisted":false,"nextItem":{"title":"1\uc8fc\ucc28: Spark \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac - \uc9c1\ub82c\ud654, Tungsten, Catalyst\uc758 \uc774\ud574","permalink":"/spark-study/blog/week-1-spark-internals-tungsten-catalyst"}},"content":"\uc2a4\ud30c\ud06c(Spark) \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc744 \uac1c\ubc1c\ud558\ub2e4 \ubcf4\uba74 Join\uc774\ub098 \uc815\ub82c(Sort) \uac19\uc740 \ubb34\uac70\uc6b4(Expensive) \uc5f0\uc0b0 \uacb0\uacfc\ub97c \uc5ec\ub7ec \ubc88 \uc7ac\uc0ac\uc6a9\ud574\uc57c \ud558\ub294 \uc0c1\ud669\uc774 \ubc18\ub4dc\uc2dc \ubc1c\uc0dd\ud55c\ub2e4. \uc774\ub54c \uc544\ubb34 \ucc98\ub9ac\ub3c4 \ud558\uc9c0 \uc54a\uc73c\uba74 \uc561\uc158(Action)\uc774 \ud638\ucd9c\ub420 \ub54c\ub9c8\ub2e4 \ub370\uc774\ud130\ub97c \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uc77d\uace0 \uacc4\uc0b0\ud558\ub294 \uc5c4\uccad\ub09c \ube44\ud6a8\uc728\uc774 \ubc1c\uc0dd\ud55c\ub2e4.\\n\\n\uc774 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\ub294 \ub450 \uac00\uc9c0 \ud575\uc2ec \ubb34\uae30\uac00 \ubc14\ub85c **\uce90\uc2f1(Caching)** \uacfc **\uccb4\ud06c\ud3ec\uc778\ud305(Checkpointing)** \uc774\ub2e4. \ub450 \uae30\ubc95\uc740 \ube44\uc2b7\ud574 \ubcf4\uc774\uc9c0\ub9cc \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\uc640 \ubaa9\uc801\uc774 \uc644\uc804\ud788 \ub2e4\ub974\ub2e4. \ucf54\ub4dc\ub97c \ud1b5\ud574 \uc774 \ub458\uc758 \ucc28\uc774\ub97c \ud655\uc778\ud55c\ub2e4.\\n\\n---\\n\\n## 1. Caching: \ube60\ub978 \uc7ac\uc0ac\uc6a9\uc744 \uc704\ud55c \uba54\ubaa8\ub9ac \ucd5c\uc801\ud654\\n\\n\uce90\uc2f1\uc740 \uacc4\uc0b0\uc774 \ub05d\ub09c DataFrame\uc774\ub098 RDD\ub97c \uba54\ubaa8\ub9ac\ub098 \ub514\uc2a4\ud06c\uc5d0 \uc784\uc2dc\ub85c \uc800\uc7a5\ud574 \ub450\ub294 \uae30\ubc95\uc774\ub2e4. \uac00\uc7a5 \ud070 \ud2b9\uc9d5\uc740 **\ub370\uc774\ud130\uc758 \uacc4\uc0b0 \uc871\ubcf4(Lineage)\ub97c \uadf8\ub300\ub85c \uc720\uc9c0**\ud55c\ub2e4\ub294 \uc810\uc774\ub2e4. \uc989, \uce90\uc2dc\ub41c \ub370\uc774\ud130\uac00 \ub0a0\uc544\uac00\uba74 \uc2a4\ud30c\ud06c\ub294 \uc5b8\uc81c\ub4e0 \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uacc4\uc0b0\ud574\uc11c \ubcf5\uad6c\ud560 \uc218 \uc788\ub2e4.\\n\\n### 1-1. DataFrame \uce90\uc2f1\uacfc StorageLevel\\n\uc2a4\ud30c\ud06c\ub294 \uc0c1\ud669\uc5d0 \ub9de\uac8c \ub370\uc774\ud130\ub97c \uc5b4\ub514\uc5d0, \uc5b4\ub5bb\uac8c \uc800\uc7a5\ud560\uc9c0 \uacb0\uc815\ud558\ub294 \ub2e4\uc591\ud55c `StorageLevel`\uc744 \uc81c\uacf5\ud55c\ub2e4.\\n\\n```scala\\nimport org.apache.spark.sql.SparkSession\\nimport org.apache.spark.storage.StorageLevel\\n\\nval spark = SparkSession.builder()\\n  .appName(\\"CachingDemo\\")\\n  .config(\\"spark.memory.offHeap.enabled\\", \\"true\\")\\n  .config(\\"spark.memory.offHeap.size\\", 10000000)\\n  .master(\\"local\\")\\n  .getOrCreate()\\n\\nval flightsDF = spark.read.option(\\"inferSchema\\", \\"true\\").json(\\"src/main/resources/data/flights\\")\\nval orderedFlightsDF = flightsDF.orderBy(\\"dist\\") // \ubb34\uac70\uc6b4 \uc5f0\uc0b0 \uac00\uc815\\n\\n// \ub2e4\uc591\ud55c \uce90\uc2f1 \uc635\uc158 \uc801\uc6a9\\norderedFlightsDF.persist(\\n  // 1. \uba54\ubaa8\ub9ac\uc5d0 \uc6d0\ubcf8 \uac1d\uccb4\ub85c \uc800\uc7a5 (\uac00\uc7a5 \ube60\ub984, OOM \uc704\ud5d8)\\n  // StorageLevel.MEMORY_ONLY \\n  \\n  // 2. \ub514\uc2a4\ud06c\uc5d0\ub9cc \uc800\uc7a5 (\uba54\ubaa8\ub9ac \uc808\uc57d, I/O\ub85c \uc778\ud574 \ub290\ub9bc)\\n  // StorageLevel.DISK_ONLY \\n  \\n  // 3. \uba54\ubaa8\ub9ac\uc5d0 \uba3c\uc800 \ucc44\uc6b0\uace0, \ub118\uce58\uba74 \ub514\uc2a4\ud06c\ub85c Spill (DF \uae30\ubcf8\uac12)\\n  // StorageLevel.MEMORY_AND_DISK \\n\\n  // 4. \uac00\ube44\uc9c0 \uceec\ub809\ud130(GC)\ub97c \ud68c\ud53c\ud558\ub294 Off-Heap \uba54\ubaa8\ub9ac \uc800\uc7a5 (Tungsten \uc5d4\uc9c4 \ud65c\uc6a9)\\n  StorageLevel.OFF_HEAP \\n)\\n\\norderedFlightsDF.count() // \uccab \ubc88\uc9f8 \uc561\uc158: \uacc4\uc0b0 \ud6c4 \uce90\uc2dc \uba54\ubaa8\ub9ac\uc5d0 \uc801\uc7ac\ub428\\norderedFlightsDF.count() // \ub450 \ubc88\uc9f8 \uc561\uc158: \uce90\uc2dc\uc5d0\uc11c \ubc14\ub85c \uc77d\uc5b4\uc640\uc11c \ud6e8\uc52c \ube60\ub984!\\n\\n// \uce90\uc2dc \uba54\ubaa8\ub9ac \ud574\uc81c\\norderedFlightsDF.unpersist()\\n```\\n\\n### 1-2. RDD \uc9c1\ub82c\ud654 \uce90\uc2f1 (\uba54\ubaa8\ub9ac \ub2e4\uc774\uc5b4\ud2b8)\\n\uc624\ub798\ub41c RDD API\ub97c \uc0ac\uc6a9\ud560 \ub54c\ub294 `_SER`(Serialized) \uc635\uc158\uc774 \ud544\uc218\uc801\uc774\ub2e4.\\n\\n```scala\\nval flightsRDD = orderedFlightsDF.rdd\\n\\n// \uc790\ubc14 \uac1d\uccb4 \ub300\uc2e0 \ubc14\uc774\ud2b8 \ubc30\uc5f4\ub85c \uc9c1\ub82c\ud654\ud558\uc5ec \uba54\ubaa8\ub9ac \uc6a9\ub7c9 \uadf9\uc801 \uc808\uac10\\nflightsRDD.persist(StorageLevel.MEMORY_ONLY_SER)\\nflightsRDD.count()\\n```\\nRDD\ub294 \ubb34\uac70\uc6b4 JVM \uac1d\uccb4\ub97c \uc0dd\uc131\ud558\uae30 \ub54c\ubb38\uc5d0 `MEMORY_ONLY`\ub97c \uc4f0\uba74 OOM\uc774 \ud130\uc9c0\uae30 \uc27d\ub2e4. \ud558\uc9c0\ub9cc DataFrame\uc744 \uc4f0\uba74 \uc2a4\ud30c\ud06c \uce74\ud0c8\ub9ac\uc2a4\ud2b8(Catalyst) \uc5d4\uc9c4\uc774 \uc54c\uc544\uc11c \ud6a8\uc728\uc801\uc778 \ubc14\uc774\ub108\ub9ac \ud3ec\ub9f7\uc73c\ub85c \uc800\uc7a5\ud574\uc8fc\uae30 \ub54c\ubb38\uc5d0 \uad73\uc774 RDD\ub85c \ubcc0\ud658\ud574\uc11c \uce90\uc2f1\ud560 \ud544\uc694\ub294 \uc5c6\ub2e4.\\n\\n---\\n\\n## 2. Checkpointing: DAG\ub97c \ub04a\uc5b4\ub0b4\ub294 \ub2e8\ub450\ub300\\n\\n\uccb4\ud06c\ud3ec\uc778\ud305\uc740 \uba54\ubaa8\ub9ac \ubd80\uc871\uc774\ub098 \ub178\ub4dc \uc7a5\uc560\ub97c \ub300\ube44\ud574, \ub370\uc774\ud130\ub97c \uc784\uc2dc\uac00 \uc544\ub2cc **HDFS\ub098 \ub85c\uceec \ub514\uc2a4\ud06c \uac19\uc740 \uc601\uad6c\uc801\uc774\uace0 \uc548\uc804\ud55c \uc800\uc7a5\uc18c\uc5d0 \ubb3c\ub9ac\uc801\uc73c\ub85c \uae30\ub85d**\ud574 \ubc84\ub9ac\ub294 \uae30\ubc95\uc774\ub2e4. \\n\\n\uac00\uc7a5 \uc911\uc694\ud55c \ucc28\uc774\ub294 **\uacc4\uc0b0 \uc871\ubcf4(Lineage, DAG)\ub97c \uc2f9\ub451 \ub04a\uc5b4\ubc84\ub9b0\ub2e4**\ub294 \uac83\uc774\ub2e4.\\n\\n\\n\\n### 2-1. Checkpointing \ucf54\ub4dc \uad6c\ud604\\n\uccb4\ud06c\ud3ec\uc778\ud305\uc744 \uc0ac\uc6a9\ud558\ub824\uba74 \ubc18\ub4dc\uc2dc \uc2a4\ud30c\ud06c \ucee8\ud14d\uc2a4\ud2b8(`sc`)\uc5d0 \uc800\uc7a5\ud560 \ub514\ub809\ud1a0\ub9ac\ub97c \uba3c\uc800 \uc9c0\uc815\ud574\uc57c \ud55c\ub2e4.\\n\\n```scala\\nval sc = spark.sparkContext\\n// \uccb4\ud06c\ud3ec\uc778\ud2b8 \uc800\uc7a5 \uacbd\ub85c \uc124\uc815 (\uc2e4\ubb34\uc5d0\uc11c\ub294 HDFS\ub098 S3 \uacbd\ub85c \uc0ac\uc6a9)\\nsc.setCheckpointDir(\\"spark-warehouse\\")\\n\\nval orderedFlights = flightsDF.orderBy(\\"dist\\")\\n\\n// checkpoint() \uc790\uccb4\uac00 \uc561\uc158(Action)\uc744 \ud2b8\ub9ac\uac70\ud558\uba70 \ub514\uc2a4\ud06c\uc5d0 \ub370\uc774\ud130\ub97c \uc4f4\ub2e4.\\nval checkpointedFlights = orderedFlights.checkpoint() \\n\\ncheckpointedFlights.count() // \ub514\uc2a4\ud06c\uc5d0\uc11c \ubc14\ub85c \uc77d\uc5b4\uc634\\n```\\n\\n### 2-2. \uc2e4\ud589 \uacc4\ud68d(Physical Plan) \ube44\uad50 \ubd84\uc11d\\n\uce90\uc2f1\uacfc \uccb4\ud06c\ud3ec\uc778\ud305\uc758 \uadfc\ubcf8\uc801\uc778 \ucc28\uc774\ub294 `explain()`\uc744 \ud1b5\ud574 \uc2e4\ud589 \uacc4\ud68d\uc744 \uc5f4\uc5b4\ubd24\uc744 \ub54c \uba85\ud655\ud558\uac8c \ub4dc\ub7ec\ub09c\ub2e4.\\n\\n**[\uc77c\ubc18 DF \ub610\ub294 \uce90\uc2f1\ub41c DF\uc758 \uc2e4\ud589 \uacc4\ud68d]**\\n```text\\norderedFlights.explain()\\n/*\\n== Physical Plan ==\\n*(1) Sort [dist#16 ASC NULLS FIRST], true, 0\\n+- *(1) Project [_id#7, arrdelay#8, ... ]\\n   +- BatchScan[...] JsonScan Location: InMemoryFileIndex[...]\\n*/\\n```\\n\uc704\ucc98\ub7fc \uce90\uc2dc\ub97c \uc4f0\ub354\ub77c\ub3c4 \uc2a4\ud30c\ud06c\ub294 \\"\uc5ec\ucc28\ud558\uba74 \ub0b4\uac00 \ud30c\uc77c\ubd80\ud130 \ub2e4\uc2dc \uc77d\uc5b4\uc11c Sort\ud560\uac8c\\"\ub77c\uba70 \uc804\uccb4 \uacc4\ud68d(Lineage)\uc744 \uae38\uac8c \ub4e4\uace0 \uc788\ub2e4.\\n\\n**[\uccb4\ud06c\ud3ec\uc778\ud2b8\ub41c DF\uc758 \uc2e4\ud589 \uacc4\ud68d]**\\n```text\\ncheckpointedFlights.explain()\\n/*\\n== Physical Plan ==\\n*(1) Scan ExistingRDD[_id#7,arrdelay#8, ... ]\\n*/\\n```\\n\uccb4\ud06c\ud3ec\uc778\ud2b8 \uc774\ud6c4\uc758 \ub370\uc774\ud130\ud504\ub808\uc784\uc740 \uc774\uc804\uc758 `Sort`, `Project`, `JsonScan` \uac19\uc740 \ubcf5\uc7a1\ud55c \uacfc\uac70\ub97c \uc644\uc804\ud788 \uc78a\uc5b4\ubc84\ub9b0\ub2e4. \uc624\uc9c1 \ub514\uc2a4\ud06c\uc5d0 \uc800\uc7a5\ub41c \uacb0\uacfc\ubb3c(`ExistingRDD`)\uc744 \uc0c8\ub85c\uc6b4 \uc2dc\uc791\uc810(Source)\uc73c\ub85c \uc0bc\ub294\ub2e4.\\n\\n---\\n\\n## 3. \uc694\uc57d \ubc0f \uc2e4\uc804 \uacb0\ub860: \uc5b8\uc81c \ubb34\uc5c7\uc744 \uc368\uc57c \ud560\uae4c?\\n\\n| \uad6c\ubd84 | Caching (\uce90\uc2f1) | Checkpointing (\uccb4\ud06c\ud3ec\uc778\ud305) |\\n| :--- | :--- | :--- |\\n| **\uc800\uc7a5 \uc704\uce58** | \uba54\ubaa8\ub9ac \uc911\uc2ec (\uc124\uc815\uc5d0 \ub530\ub77c \ub514\uc2a4\ud06c \ud63c\uc6a9) | \uc601\uad6c \uc800\uc7a5\uc18c (HDFS, S3, \ub85c\uceec \ub514\uc2a4\ud06c \ub4f1) |\\n| **Lineage (\uc871\ubcf4)** | \uc720\uc9c0\ub428 (\uc7a5\uc560 \uc2dc \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uacc4\uc0b0) | **\ub2e8\uc808\ub428** (\uacfc\uac70 \uc5f0\uc0b0 \uae30\ub85d \uc0ad\uc81c) |\\n| **\uc18d\ub3c4** | \ub9e4\uc6b0 \ube60\ub984 (\ud2b9\ud788 \uba54\ubaa8\ub9ac Hit \uc2dc) | \uc0c1\ub300\uc801\uc73c\ub85c \ub290\ub9bc (\ub514\uc2a4\ud06c I/O \ubc1c\uc0dd) |\\n| **\ubaa9\uc801** | \ubc18\ubcf5 \uc5f0\uc0b0 \uc18d\ub3c4 \ud5a5\uc0c1 | \uc7a5\uc560 \ubcf5\uad6c, \uae34 \uc5f0\uc0b0 \uccb4\uc778 \ub04a\uae30 |\\n\\n### \ud83d\ude80 Caching\uc744 \uc368\uc57c \ud560 \ub54c (Performance Focus)\\n* \ub3d9\uc77c\ud55c \uc7a1(Job) \uc548\uc5d0\uc11c \uba38\uc2e0\ub7ec\ub2dd \ubaa8\ub378\uc744 \ubc18\ubcf5 \ud559\uc2b5\uc2dc\ud0ac \ub54c.\\n* \ub8e9\uc5c5 \ud14c\uc774\ube14(Lookup Table)\ucc98\ub7fc \uc790\uc8fc \uc870\uc778\ub418\ub294 \uc791\uc740 DataFrame\uc744 \uc7ac\uc0ac\uc6a9\ud560 \ub54c.\\n* \uc5f0\uc0b0 \uc18d\ub3c4\ub97c \uc950\uc5b4\uc9dc\uc57c \ud558\ub294 \uc0c1\ud669\uc77c \ub54c.\\n\\n### \ud83d\udee1\ufe0f Checkpointing\uc744 \uc368\uc57c \ud560 \ub54c (Reliability Focus)\\n* **\ubc30\uce58 \uc791\uc5c5 \uc2dc\uac04\uc774 \ub108\ubb34 \uae38\uc5b4\uc11c** \uc911\uac04\uc5d0 \uc5d0\ub7ec\uac00 \ub0ac\uc744 \ub54c \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \ub3cc\ub9ac\ub294 \uac83\uc774 \uc7ac\uc559\uc778 \uacbd\uc6b0.\\n* DataFrame\uc758 `withColumn`\uc774\ub098 `join` \ubcc0\ud658\uc774 \uc218\uc2ed, \uc218\ubc31 \ubc88 \uacb9\uccd0\uc11c **\uc2e4\ud589 \uacc4\ud68d(DAG)\uc774 \ub108\ubb34 \uae38\uc5b4\uc9c0\uace0 \uba54\ubaa8\ub9ac\ub97c \ub9ce\uc774 \uba39\uc5b4 \ub4dc\ub77c\uc774\ubc84\uc5d0\uc11c `StackOverflowError`\uac00 \ud130\uc9c8 \uc704\ud5d8**\uc774 \uc788\uc744 \ub54c. (\uc774\ub54c \uccb4\ud06c\ud3ec\uc778\ud2b8\ub97c \ud55c \ubc88\uc529 \ucc0d\uc5b4\uc8fc\uba74 DAG\uac00 \ucd08\uae30\ud654\ub418\uc5b4 \uc5d0\ub7ec\ub97c \ub9c9\uc744 \uc218 \uc788\ub2e4.)\\n* Spark Structured Streaming \uc6b4\uc601 \uc2dc \uc7a5\uc560 \ubcf5\uad6c\ub97c \uc704\ud574.\\n\\n### \ud83d\udca1 \uc2e4\ubb34 \uc6b4\uc601 \ud301\\n\ud604\uc5c5\uc5d0\uc11c\ub294 \uae34 \ub370\uc774\ud130 \ud30c\uc774\ud504\ub77c\uc778\uc744 \uc124\uacc4\ud560 \ub54c, \uc911\uac04\uc911\uac04 \ubb34\uac70\uc6b4 \uc154\ud50c(Shuffle)\uc774 \ub05d\ub098\ub294 \uc9c0\uc810\uc5d0 **\uce90\uc2f1\uacfc \uccb4\ud06c\ud3ec\uc778\ud305\uc744 \ud568\uaed8 \uc0ac\uc6a9**\ud558\uae30\ub3c4 \ud55c\ub2e4. \ub370\uc774\ud130\ub97c \uba54\ubaa8\ub9ac\uc5d0 \uc62c\ub824 \ube60\ub974\uac8c \uc7ac\uc0ac\uc6a9\ud558\uba74\uc11c\ub3c4, \ub514\uc2a4\ud06c\uc5d0 \uc548\uc804\ud558\uac8c \ubc31\uc5c5\ud574\ub450\uc5b4 DAG\ub97c \uc790\ub974\uace0 \uc7a5\uc560\uc5d0 \ub300\ube44\ud558\ub294 \ud6cc\ub96d\ud55c \uc804\ub7b5\uc774\ub2e4."},{"id":"week-1-spark-internals-tungsten-catalyst","metadata":{"permalink":"/spark-study/blog/week-1-spark-internals-tungsten-catalyst","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-02-22-spark-serilization-tungsten-catalyst-kwon.md","source":"@site/blog/2026-02-22-spark-serilization-tungsten-catalyst-kwon.md","title":"1\uc8fc\ucc28: Spark \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac - \uc9c1\ub82c\ud654, Tungsten, Catalyst\uc758 \uc774\ud574","description":"\uc2a4\ud30c\ud06c RDD, DataFrame, Dataset\uc758 \uc131\ub2a5 \ucc28\uc774\ub97c \ub9cc\ub4dc\ub294 \uc9c1\ub82c\ud654\uc758 \ube44\ubc00\uacfc Tungsten \uc5d4\uc9c4, Catalyst \uc635\ud2f0\ub9c8\uc774\uc800\uc758 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uc124\uba85\ud55c\ub2e4.","date":"2026-02-22T00:00:00.000Z","tags":[{"inline":true,"label":"spark","permalink":"/spark-study/blog/tags/spark"},{"inline":true,"label":"scala","permalink":"/spark-study/blog/tags/scala"},{"inline":true,"label":"optimization","permalink":"/spark-study/blog/tags/optimization"},{"inline":true,"label":"tungsten","permalink":"/spark-study/blog/tags/tungsten"},{"inline":true,"label":"catalyst","permalink":"/spark-study/blog/tags/catalyst"},{"inline":true,"label":"serialization","permalink":"/spark-study/blog/tags/serialization"}],"readingTime":5.01,"hasTruncateMarker":false,"authors":[{"name":"Kwon Younglin","title":"Data Engineer","url":"https://github.com/kwonyl14","imageURL":"https://github.com/kwonyl14.png","key":"kwonyl14","page":null}],"frontMatter":{"slug":"week-1-spark-internals-tungsten-catalyst","title":"1\uc8fc\ucc28: Spark \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac - \uc9c1\ub82c\ud654, Tungsten, Catalyst\uc758 \uc774\ud574","authors":["kwonyl14"],"tags":["spark","scala","optimization","tungsten","catalyst","serialization"],"description":"\uc2a4\ud30c\ud06c RDD, DataFrame, Dataset\uc758 \uc131\ub2a5 \ucc28\uc774\ub97c \ub9cc\ub4dc\ub294 \uc9c1\ub82c\ud654\uc758 \ube44\ubc00\uacfc Tungsten \uc5d4\uc9c4, Catalyst \uc635\ud2f0\ub9c8\uc774\uc800\uc758 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uc124\uba85\ud55c\ub2e4."},"unlisted":false,"prevItem":{"title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","permalink":"/spark-study/blog/week-1-caching-vs-checkpointing"}},"content":"\uc2a4\ud30c\ud06c(Spark) \uac15\uc758\ub97c \ubcf4\ub2e4\uac00 \uc5b4\ub5a4 \ub450\uac00\uc9c0 df\ub97c repartition(7), repartition(9)\uc73c\ub85c \ub9cc\ub4e0 \ud6c4 join\uc744 \uc2dc\ub3c4\ud558\ub294 \uc608\uc81c\ub97c \ubd24\ub2e4. \uc131\ub2a5\uacfc \uad00\ub828\uc5c6\uc774 repartition\ud560 \ub54c\uc640 join\ud560 \ub54c\uc5d0 \uc5b4\ub5a4 explain()\uc774 \uc774\ub8e8\uc5b4\uc9c0\ub294\uc9c0 \ud655\uc778\ud558\ub294 \uc608\uc81c\uc600\uc9c0\ub9cc \uc2e4\uc81c\ub85c join\uc804\uc5d0 repartition\uc744 \ud55c \ubc88 \ud574\uc900\ub2e4\uba74 \ube44\ud6a8\uc728\uc801\uc778\uc9c0 \uad81\uae08\ud574\uc84c\ub2e4.\\n\ub610\ud55c \ucd5c\uc801\ud654\ub97c \uc704\ud574 \ud145\uc2a4\ud150 \uc5d4\uc9c4\uacfc \uce74\ud0c8\ub9ac\uc2a4\ud2b8\uc5d0 \ub300\ud55c \uc774\ud574\uac00 \ud544\uc694\ud574 \uc774 \uae00\uc5d0\uc11c \uc124\uba85\ud55c\ub2e4. \\n\\n---\\n\\n## 1. \uc870\uc778(Join) \uc804 Repartitioning, \uacfc\uc5f0 \uc131\ub2a5\uc5d0 \ub3c4\uc6c0\uc774 \ub420\uae4c?\\n\\n1,000\ub9cc \uac74\uc758 \ub370\uc774\ud130\uc640 2,000\ub9cc \uac74\uc758 \ub370\uc774\ud130\ub97c \uc870\uc778(Join)\ud574\uc57c \ud558\ub294 \uc0c1\ud669\uc744 \uac00\uc815\ud574 \ubcf4\uc790. \uc774\ub54c \\"\uc870\uc778 \uc804\uc5d0 \ubbf8\ub9ac `repartition(10)` \uc815\ub3c4\ub85c \ud30c\ud2f0\uc158\uc744 \uc798\uac8c \ub610\ub294 \uade0\ub4f1\ud558\uac8c \ucabc\uac1c\ub450\uba74 \ubcd1\ub82c \ucc98\ub9ac\uac00 \uc798 \ub3fc\uc11c \ube60\ub974\uc9c0 \uc54a\uc744\uae4c?\\"\ub77c\uace0 \uc0dd\uac01\ud560 \uc218 \ub3c4 \uc788\uaca0\ub2e4.\\n\\n\uc544\ub798\uc640 \uac19\uc740 \uc0c1\ud669\uc5d0\uc11c repartition\uc740 \ud6a8\uc728\uc801\uc77c\uae4c?\\n\\n```scala  \\n  val ds1 = spark.range(1, 10000000)\\n  val ds2 = spark.range(1, 20000000, 2)\\n  val ds3 = ds1.repartition(7)\\n  val ds4 = ds2.repartition(9)\\n  val ds5 = ds3.selectExpr(\\"id * 3 as id\\")\\n  val joined = ds5.join(ds4, \\"id\\")\\n  val sum = joined.selectExpr(\\"sum(id)\\")\\n  sum.explain()\\n```\\n\\n\uc9c1\uc811 \uc2e4\ud589\ud574\ubcf8 \uacb0\uacfc \ub9ac\ud30c\ud2f0\uc158 \ucf54\ub4dc\ub97c \ube7c\uace0 join\ud574\ubcf4\ub2c8 \uc18d\ub3c4\uac00 \ub2e8\ucd95\ub418\uc5c8\ub2e4.\\n![alt text](image.png)\\n\\n\\n\uacb0\ub860\uc740 **\ud2b9\ubcc4\ud55c \ubaa9\uc801(Join Key \uae30\ubc18\uc758 \ud30c\ud2f0\uc154\ub2dd)\uc774 \uc5c6\ub2e4\uba74 \uc870\uc778 \uc804\uc758 \ub2e8\uc21c\ud55c repartition()\uc740 \uc131\ub2a5\uc744 \ub192\uc5ec\uc8fc\uc9c0 \uc54a\ub294\ub2e4.(\uc624\ud788\ub824 \ub0ae\uc544\uc9c4\ub2e4.)**\\n\\n\\n\\n### \uc870\uc778\uacfc \uc154\ud50c \ud30c\ud2f0\uc158\uc758 \uad00\uacc4\\n\uc2a4\ud30c\ud06c\uc5d0\uc11c \ub450 \ub370\uc774\ud130\ub97c \uc870\uc778\ud560 \ub54c\ub294 \ubc18\ub4dc\uc2dc **\uc154\ud50c(Shuffle)** \uc774 \ubc1c\uc0dd\ud55c\ub2e4. \uc2a4\ud30c\ud06c\ub294 \uac19\uc740 \uc870\uc778 \ud0a4(Key)\ub97c \uac00\uc9c4 \ub370\uc774\ud130\ub97c \uac19\uc740 \ud30c\ud2f0\uc158(\ub178\ub4dc)\uc73c\ub85c \ubaa8\uc73c\uae30 \uc704\ud574 \ub370\uc774\ud130\ub97c \ub124\ud2b8\uc6cc\ud06c \ub108\uba38\ub85c \uc7ac\ubd84\ubc30\ud558\ub294\ub370, \uc774\ub54c \uae30\ubcf8\uc801\uc73c\ub85c `spark.sql.shuffle.partitions` \uc124\uc815\uac12(\uae30\ubcf8\uac12 200)\uc5d0 \ub530\ub77c \ub370\uc774\ud130\ub97c 200\uac1c\uc758 \ud30c\ud2f0\uc158\uc73c\ub85c \ucabc\uac20\ub2e4.\\n\\n\ub9cc\uc57d \uc870\uc778 \uc804\uc5d0 `repartition(10)`\uc744 \ud55c\ub2e4\uba74 \uc2a4\ud30c\ud06c\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 \ub3d9\uc791\ud55c\ub2e4.\\n1. \uc544\ubb34\ub7f0 \uae30\uc900 \uc5c6\uc774 \ub77c\uc6b4\ub4dc \ub85c\ube48(Round-Robin) \ubc29\uc2dd\uc73c\ub85c \ub370\uc774\ud130\ub97c 10\uac1c\uc758 \ud30c\ud2f0\uc158\uc73c\ub85c \uc11e\ub294\ub2e4. **(1\ucc28 \uc154\ud50c \ubc1c\uc0dd - \ub124\ud2b8\uc6cc\ud06c I/O \ub0ad\ube44)**\\n2. \uc870\uc778 \uc5f0\uc0b0\uc744 \ub9cc\ub098\uba74 \uc870\uc778 \ud0a4\ub97c \uae30\uc900\uc73c\ub85c \ub2e4\uc2dc \ub370\uc774\ud130\ub97c 200\uac1c\uc758 \ud30c\ud2f0\uc158\uc73c\ub85c \uc11e\ub294\ub2e4. **(2\ucc28 \uc154\ud50c \ubc1c\uc0dd)**\\n\\n\uc989, \uc758\ubbf8 \uc5c6\ub294 \uc154\ud50c\uc744 \ud55c \ubc88 \ub354 \uc720\ubc1c\ud558\uc5ec \uc131\ub2a5\ub9cc \ub5a8\uc5b4\ub728\ub9ac\uac8c \ub41c\ub2e4. **\uc5b4\ucc28\ud53c \uc870\uc778\uc774 \ubc1c\uc0dd\ud558\uba74 \uc2a4\ud30c\ud06c\uac00 \uc54c\uc544\uc11c \uc870\uc778 \ud0a4\ub97c \uae30\uc900\uc73c\ub85c 200\uac1c\ub85c \ub9ac\ud30c\ud2f0\uc154\ub2dd\uc744 \ud574\uc8fc\uae30 \ub54c\ubb38\uc5d0, \uc2a4\ud30c\ud06c \uc5d4\uc9c4\uc744 \ubbff\uace0 \uadf8\ub300\ub85c \uc870\uc778\ud558\ub294 \uac83\uc774 \uac00\uc7a5 \ube60\ub974\ub2e4.**\\n\\n---\\n\\n## 2. API\ubcc4 \uadf9\ub2e8\uc801 \uc131\ub2a5 \ucc28\uc774: \uc9c1\ub82c\ud654(Serialization)\\n\\n\uac19\uc740 10\uc5b5 \uac74\uc758 \ub370\uc774\ud130\ub97c \uc138\ub294(`count()`) \uc791\uc5c5\uc778\ub370, \uc65c API\uc5d0 \ub530\ub77c 16\ucd08\uac00 \uac78\ub9ac\uae30\ub3c4 \ud558\uace0 0.1\ucd08 \ub9cc\uc5d0 \ub05d\ub098\uae30\ub3c4 \ud560\uae4c? \uc544\ub798 \ucf54\ub4dc\ub97c \ud1b5\ud574 \uc6d0\uc778\uc744 \ubd84\uc11d\ud574 \ubcf8\ub2e4.\\n\\n```scala\\nval sc = spark.sparkContext\\n// 1. RDD\ub97c \uc0dd\uc131\ud558\uace0 DataFrame\uc73c\ub85c \ubcc0\ud658 \ud6c4 Count\\nval rdd = sc.parallelize(1 to 1000000000)\\nval df = rdd.toDF(\\"id\\")\\ndf.count() // \uc57d 16\ucd08 \uc18c\uc694 (\ub9e4\uc6b0 \ub290\ub9bc)\\n\\n// 2. \ucc98\uc74c\ubd80\ud130 Dataset/DataFrame\uc73c\ub85c \uc0dd\uc131 \ud6c4 Count\\nval ds = spark.range(1, 1000000000)\\nds.count() // 0.1\ucd08 \uc18c\uc694 (\ub9e4\uc6b0 \ube60\ub984)\\n```\\n\\n### 16\ucd08 vs 0.1\ucd08 \ucc28\uc774 \ub098\ub294 \uc774\uc720\\n* `sc.parallelize`\ub97c \uc0ac\uc6a9\ud558\uba74 10\uc5b5 \uac1c\uc758 \ubb34\uac70\uc6b4 `java.lang.Integer` **JVM \uac1d\uccb4** \uac00 \uba54\ubaa8\ub9ac(Heap)\uc5d0 \uc0dd\uc131\ub41c\ub2e4. \uc774\ub97c DataFrame\uc73c\ub85c \ubcc0\ud658(`toDF`)\ud558\ub824\uba74, \uc2a4\ud30c\ud06c\ub294 10\uc5b5 \uac1c\uc758 \uac1d\uccb4\ub97c \uc77c\uc77c\uc774 \uaebc\ub0b4\uc11c \uc2a4\ud30c\ud06c\uc758 \ub0b4\ubd80 \ubc14\uc774\ub108\ub9ac \ud3ec\ub9f7\uc73c\ub85c **\uc9c1\ub82c\ud654(SerializeFromObject)** \ud558\ub294 \uc5c4\uccad\ub09c \ub178\uac00\ub2e4\ub97c \ud574\uc57c \ud55c\ub2e4. \uc774 \ubcc0\ud658 \ube44\uc6a9\uc774 16\ucd08\ub098 \uac78\ub9b0 \uac83\uc774\ub2e4.\\n* \ubc18\uba74 `spark.range`\ub294 \uc560\ucd08\uc5d0 JVM \uac1d\uccb4\ub97c \ub9cc\ub4e4\uc9c0 \uc54a\ub294\ub2e4. \ucc98\uc74c\ubd80\ud130 \ud145\uc2a4\ud150(Tungsten) \uc5d4\uc9c4\uc774 \uc88b\uc544\ud558\ub294 \ubc14\uc774\ub108\ub9ac \ud3ec\ub9f7\uc73c\ub85c \uba54\ubaa8\ub9ac\uc5d0 \ub370\uc774\ud130\ub97c \ubc00\uc5b4 \ub123\uae30 \ub54c\ubb38\uc5d0 0.1\ucd08 \ub9cc\uc5d0 \uc5f0\uc0b0\uc774 \ub05d\ub09c\ub2e4.\\n\\n\\n\\n### \ub78c\ub2e4(Lambda) \ud568\uc218\\nDataset\uc740 \ube60\ub974\uc9c0\ub9cc, \uc2a4\uce7c\ub77c\uc758 \uc775\uba85 \ud568\uc218(\ub78c\ub2e4)\ub97c \uc4f0\uac8c\ub418\uba74 \uc131\ub2a5 \uc800\ud558\uac00 \uc77c\uc5b4\ub09c\ub2e4.\\n\\n```scala\\n// DS\uc758 \uac01 \uc694\uc18c\uc5d0 5\ub97c \uacf1\ud558\ub294 \uc5f0\uc0b0\\nval dsTimes5 = ds.map(_ * 5)\\ndsTimes5.selectExpr(\\"count(*)\\").show() // \uac11\uc790\uae30 7\ucd08\ub85c \ub290\ub824\uc9d0 (70\ubc30 \uc99d\uac00)\\n```\\n\\n\uc2e4\ud589 \uacc4\ud68d(`explain()`)\uc744 \ubcf4\uba74 \uc774\uc720\ub97c \uba85\ud655\ud788 \uc54c \uc218 \uc788\ub2e4.\\n\uc2a4\ud30c\ud06c \uc5d4\uc9c4 \uc785\uc7a5\uc5d0\uc11c `_ * 5` \ub77c\ub294 \uc2a4\uce7c\ub77c \ucf54\ub4dc\ub294 \uc18d\uc744 \uc54c \uc218 \uc5c6\ub294 \ube14\ub799\ubc15\uc2a4\ub2e4. \ucd5c\uc801\ud654\ub41c \ubc14\uc774\ub108\ub9ac \ub370\uc774\ud130\ub97c \uc5f0\uc0b0\ud558\uae30 \uc704\ud574 \uc5b4\uca54 \uc218 \uc5c6\uc774 \ub2e4\uc2dc JVM \uac1d\uccb4\ub85c **\uc5ed\uc9c1\ub82c\ud654(DeserializeToObject)\ud558\uace0,** \uc5f0\uc0b0\uc774 \ub05d\ub098\uba74 \ub2e4\uc2dc **\uc9c1\ub82c\ud654(SerializeFromObject)\ud574\uc57c** \ud55c\ub2e4. \\n\\n**\ud83d\udca1 \ud574\uacb0\ubc29\ubc95:** \uac00\ub2a5\ud558\uba74 `ds.map(_ * 5)` \ub300\uc2e0, \uc2a4\ud30c\ud06c\uac00 \uc774\ud574\ud560 \uc218 \uc788\ub294 \uceec\ub7fc \ud45c\ud604\uc2dd\uc778 `df.select($\\"id\\" * 5)`\ub97c \uc0ac\uc6a9\ud558\uba74 \uc9c1\ub82c\ud654 \ube44\uc6a9 \uc5c6\uc774 \ud145\uc2a4\ud150 \uc5d4\uc9c4\uc73c\ub85c \ucc98\ub9ac\ub418\uae30 \ub54c\ubb38\uc5d0 \uacb0\uacfc\ub294 \uac19\uc9c0\ub9cc \uc9c1\ub82c\ud654 \uacfc\uc815 \uc5c6\uc774 \uc989\uc2dc \uc5f0\uc0b0\ub41c\ub2e4. \ud55c \ubc88 DataFrame\uc744 \uc120\ud0dd\ud588\ub2e4\uba74 \ub05d\uae4c\uc9c0 DataFrame\uc758 DSL(\ub0b4\uc7a5 \ud568\uc218)\uc744 \uc720\uc9c0\ud558\ub294 \uac83\uc774 \ud575\uc2ec\uc774\ub2e4.\\n\\n---\\n\\n## 3. \ud145\uc2a4\ud150(Tungsten) \uc5d4\uc9c4\uacfc Whole-Stage CodeGen\\n\\n\ud145\uc2a4\ud150(Tungsten)\uc740 JVM\uc758 \ud55c\uacc4\ub97c \uadf9\ubcf5\ud558\uace0 \ud558\ub4dc\uc6e8\uc5b4(CPU, \uba54\ubaa8\ub9ac)\uc758 \uc131\ub2a5\uc744 \uadf9\ud55c\uae4c\uc9c0 \ub04c\uc5b4\uc62c\ub9ac\uae30 \uc704\ud55c \uc2a4\ud30c\ud06c\uc758 \ud575\uc2ec \uc5d4\uc9c4\uc774\ub2e4. \ud145\uc2a4\ud150 \uc5d4\uc9c4\uc774 \ubc1c\ub3d9\ub418\ub294 \uac00\uc7a5 \ub300\ud45c\uc801\uc778 \ucd5c\uc801\ud654 \uae30\uc220\uc774 \ubc14\ub85c **\uc804\uccb4 \uc2a4\ud14c\uc774\uc9c0 \ucf54\ub4dc \uc0dd\uc131(Whole-Stage Code Generation)\uc774\ub2e4.**\\n\\n\uc544\ub798 \ucf54\ub4dc\ub97c \ud1b5\ud574 \ud145\uc2a4\ud150 \uc5d4\uc9c4\uc744 \uaed0\ub2e4 \ucf30\uc744 \ub54c\uc758 \ucc28\uc774\ub97c \uc0b4\ud3b4\ubcf4\uc790.\\n\\n```scala\\n// 1. \ud145\uc2a4\ud150 \uc5d4\uc9c4 \uac15\uc81c \ub044\uae30\\nspark.conf.set(\\"spark.sql.codegen.wholeStage\\", \\"false\\")\\nval noWholeStageSum = spark.range(1000000).selectExpr(\\"sum(id)\\")\\nnoWholeStageSum.explain()\\n/*\\n== Physical Plan ==\\nHashAggregate(keys=[], functions=[sum(id#54L)])\\n+- HashAggregate(keys=[], functions=[partial_sum(id#54L)])\\n   +- Range (0, 1000000, step=1, splits=1)\\n*/\\n\\n// 2. \ud145\uc2a4\ud150 \uc5d4\uc9c4 \ucf1c\uae30 (\uae30\ubcf8\uac12)\\nspark.conf.set(\\"spark.sql.codegen.wholeStage\\", \\"true\\")\\nval wholeStageSum = spark.range(1000000).selectExpr(\\"sum(id)\\")\\nwholeStageSum.explain()\\n/*\\n== Physical Plan ==\\n*(1) HashAggregate(keys=[], functions=[sum(id#67L)])\\n+- *(1) HashAggregate(keys=[], functions=[partial_sum(id#67L)])\\n   +- *(1) Range (0, 1000000, step=1, splits=1)\\n*/\\n```\\n\\n### \uc2e4\ud589 \uacc4\ud68d\uc758 \ubcc4\ud45c(`*`)\uac00 \uc758\ubbf8\ud558\ub294 \uac83\\n\ud145\uc2a4\ud150 \uc5d4\uc9c4\uc744 \ucf1c\uace0 `explain()`\uc744 \ud638\ucd9c\ud558\uba74 \ub178\ub4dc \uc55e\uc5d0 `*(1)` \uc774\ub77c\ub294 \ubcc4\ud45c\uac00 \ubd99\ub294\ub2e4. \uc774\uac83\uc774 \ubc14\ub85c **Tungsten\uc774 \uac1c\uc785\ud558\uc5ec Whole-Stage CodeGen\uc774 \uc801\uc6a9\ub418\uc5c8\ub2e4\ub294 \ud45c\uc2dc\uc774\ub2e4.**\\n\\n\\n---\\n\\n## 4. \uce74\ud0c8\ub9ac\uc2a4\ud2b8(Catalyst): \ucffc\ub9ac \ud50c\ub79c \ucd5c\uc801\ud654\\n\\n\ud145\uc2a4\ud150\uc774 \ubb3c\ub9ac\uc801\uc778 \uc5f0\uc0b0 \uc18d\ub3c4\ub97c \ub192\uc778\ub2e4\uba74, **\uce74\ud0c8\ub9ac\uc2a4\ud2b8(Catalyst) \uc635\ud2f0\ub9c8\uc774\uc800**\ub294 \ucffc\ub9ac\uc758 \ub17c\ub9ac\uc801\uc778 \uad6c\uc870 \uc790\uccb4\ub97c \uac00\uc7a5 \ud6a8\uc728\uc801\uc778 \uacbd\ub85c\ub97c \ucc3e\uc544\uc900\ub2e4.\\n\\n```scala\\nval flights = spark.read.option(\\"inferSchema\\", \\"true\\").json(\\"src/main/resources/data/flights\\")\\n\\n// \uc758\uc0ac\uc18c\ud1b5 \ubd80\uc7ac\ub85c \uc778\ud574 \ub611\uac19\uc740 \ub370\uc774\ud130\ub97c \ud544\ud130\ub9c1\ud558\ub294 \uc911\ubcf5 \ucf54\ub4dc\uac00 \ubc1c\uc0dd\ud55c \uc0c1\ud669\\ndef filterTeam1(flights: DataFrame) = flights.where($\\"origin\\" =!= \\"LGA\\").where($\\"dest\\" === \\"DEN\\")\\ndef filterTeam2(flights: DataFrame) = flights.where($\\"origin\\" =!= \\"EWR\\").where($\\"dest\\" === \\"DEN\\")\\n\\nval filterBoth = filterTeam1(filterTeam2(flights))\\nfilterBoth.explain(true)\\n```\\n\uc5ec\ub7ec \uac1c\ubc1c\uc790\uac00 \ud611\uc5c5\ud558\ub2e4 \ubcf4\uba74 \uc704\ucc98\ub7fc \ube44\ud6a8\uc728\uc801\uc778 \ud544\ud130\ub9c1(`where`)\uc774 \uc911\ucca9\ub420 \uc218 \uc788\ub2e4. \ud558\uc9c0\ub9cc \uce74\ud0c8\ub9ac\uc2a4\ud2b8\ub294 \ubb3c\ub9ac\uc801 \uc2e4\ud589 \uacc4\ud68d\uc744 \uc9dc\uae30 \uc804\uc5d0 \uc774 \ub17c\ub9ac\ub4e4\uc744 \ubd84\uc11d\ud558\uc5ec **\uc911\ubcf5\uc744 \uc81c\uac70\ud558\uace0 \uc870\uac74\ub4e4\uc744 \ud558\ub098\uc758 \uae54\ub054\ud55c \uc2dd\uc73c\ub85c \ud569\uccd0\uc900\ub2e4.**\\n\\n\\n\\n### \ud30c\ud2f0\uc158/\ud544\ud130 \ud478\uc2dc\ub2e4\uc6b4 (Pushdown)\\n\uce74\ud0c8\ub9ac\uc2a4\ud2b8\uc758 \uac00\uc7a5 \ubb34\uc11c\uc6b4 \uc810\uc740 \uc18c\uc2a4(Parquet \ub4f1)\uc5d0\uc11c \ub370\uc774\ud130\ub97c \uc77d\uc744 \ub54c \ubc1c\ud718\ub41c\ub2e4.\\n\\n```scala\\nval notFromLGA = spark.read.load(\\"src/main/resources/data/flights_parquet\\")\\n  .where($\\"origin\\" =!= \\"LGA\\")\\n```\\n\uc774 \ucf54\ub4dc\ub97c \uc2e4\ud589\ud558\uba74, \uc2a4\ud30c\ud06c\ub294 \uba54\ubaa8\ub9ac\uc5d0 \ub370\uc774\ud130\ub97c \ub2e4 \uc62c\ub824\ub193\uace0 \ud544\ud130\ub9c1\uc744 \ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, **\ub514\uc2a4\ud06c(Parquet)\uc5d0\uc11c \ub370\uc774\ud130\ub97c \uc77d\uc5b4 \ub4e4\uc77c \ub54c\ubd80\ud130 \uc774\ubbf8 \\"LGA\\"\uac00 \uc544\ub2cc \ub370\uc774\ud130\ub9cc \uace8\ub77c\uc11c \uc77d\uc5b4\uc628\ub2e4.** \uc774\ub97c \ud544\ud130 \ud478\uc2dc\ub2e4\uc6b4(Filter Pushdown)\uc774\ub77c\uace0 \ud558\uba70, \ubd88\ud544\uc694\ud55c I/O\ub97c \uc6d0\ucc9c \ucc28\ub2e8\ud558\uc5ec \uc131\ub2a5\uc744 \uae30\ud558\uae09\uc218\uc801\uc73c\ub85c \ub192\uc5ec\uc900\ub2e4.\\n\\n---\\n\\n## \ud83d\udcdd \ucd5c\uc885 \uacb0\ub860 (Best Practices)\\n1. \uc870\uc778 \uc5f0\uc0b0 \uc804 \uc758\ubbf8 \uc5c6\ub294 `repartition()`\uc740 \uc131\ub2a5\uc800\ud558\ub97c \ubd88\ub7ec\uc62c \uc218 \uc788\ub2e4.\\n2. \uc2a4\ud30c\ud06c \ucf54\ub4dc\ub97c \uc9e4 \ub54c\ub294 \ubb34\uac70\uc6b4 \uac1d\uccb4\ub97c \ub9cc\ub4dc\ub294 RDD\ub098 `ds.map()` \uac19\uc740 \ub78c\ub2e4 \ud568\uc218 \uc0ac\uc6a9\uc744 \ud53c\ud558\uace0, \uac00\uae09\uc801 **DataFrame\uc758 \ub0b4\uc7a5 \ud568\uc218(DSL)\ub97c** \uc0ac\uc6a9\ud574 \uc9c1\ub82c\ud654\ub97c \ud53c\ud558\ub294 \uac83\uc774 \ucd5c\uc801\ud654 \ud301\uc774\ub2e4.\\n3. \uc2a4\ud30c\ud06c\ub294 \ud145\uc2a4\ud150(Whole-Stage CodeGen)\uacfc \uce74\ud0c8\ub9ac\uc2a4\ud2b8(Pushdown)\ub77c\ub294 \ube60\ub978 \uc790\uccb4 \uc5d4\uc9c4\uc744 \uac00\uc9c0\uace0 \uc788\ub2e4. \ubd88\ud544\uc694\ud590\uac8c \uc9c1\ub82c\ud654\ub97c \ud558\uc9c0 \uc54a\uace0 \ud145\uc2a4\ud150 \uc5d4\uc9c4\uc744 \ucd5c\ub300\ud55c \ud65c\uc6a9\ud558\ub294 \ucf54\ub4dc \uc791\uc131\ud558\ub294 \uac83\uc774 \ud544\uc694\ud558\ub2e4."}]}}')}}]);